const materiais = ['Metálica', 'Plástica'];
const esperado = materiais[Math.floor(Math.random() * materiais.length)];
const erro = Math.random() < 0.12;
let detectado;
if (erro) {
    const opcoes = materiais.filter(m => m !== esperado).concat([null]);
    detectado = opcoes[Math.floor(Math.random() * opcoes.length)];
} else {
    detectado = esperado;
}
flow.set('esperado', esperado);
flow.set('detectado', detectado);

msg.method = 'POST';
msg.url = 'http://backend:8080/api/Monitoramento';
msg.headers = { 'content-type': 'application/json' };
msg.payload = { idSensor: 1, estado: detectado === 'Metálica' ? 'on' : 'off' };
return msg;

const detectado = flow.get('detectado');
msg.method = 'POST';
msg.url = 'http://backend:8080/api/Monitoramento';
msg.headers = { 'content-type': 'application/json' };
msg.payload = { idSensor: 2, estado: detectado === 'Plástica' ? 'on' : 'off' };
return msg;

msg.method = 'POST';
msg.url = 'http://backend:8080/api/Monitoramento';
msg.headers = { 'content-type': 'application/json' };
msg.payload = { idSensor: 3, estado: 'on' };
return msg;

msg.method = 'POST';
msg.url = 'http://backend:8080/api/Processamento/processar-peca';
msg.headers = { 'content-type': 'application/json' };
msg.payload = { tipoMaterialEsperado: flow.get('esperado') };
return msg;
